```class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        vector<int> cnt(26, 0), tgt(26, 0);
        for (char c : s) cnt[c - 'a']++;
        for (char c : target) tgt[c - 'a']++;
        int res = INT_MAX;
        for (int i = 0; i < 26; i++) {
            if (tgt[i] > 0) res = min(res, cnt[i] / tgt[i]);
        }
        return res;
    }
};
